.darma-loader-darma-custom-115 {
  width: 50px;
  aspect-ratio: 1;
  display: grid;
}
.darma-loader-darma-custom-115:before,
.darma-loader-darma-custom-115:after {
  content: "";
  grid-area: 1/1;
  border-radius: 50%;
  background: var(--loader-color, #f03355);
  -webkit-mask:repeating-linear-gradient(var(--loader-secondary-color, #000) 0 5px,#0000 0 10px);
  animation: darma-loader-darma-custom-115-l35 1.5s infinite;
}
.darma-loader-darma-custom-115:after {
  -webkit-mask:repeating-linear-gradient(#0000 0 5px,var(--loader-secondary-color, #000) 0 10px);
  --s:-1;
}
@keyframes darma-loader-darma-custom-115-l35 {
  0%,
  10% {transform: translate(0) rotate(0)}
  35% {transform: translate(calc(var(--s,1)*50%)) rotate(0)}
  66% {transform: translate(calc(var(--s,1)*50%)) rotate(calc(var(--s,1)*180deg))}
  90%,
  100% {transform: translate(0) rotate(calc(var(--s,1)*180deg))}
}

